import os
import json
import argparse
from openai import OpenAI
import re
from statistics import mean

# This script adapts the rubric-based evaluation methodology from ResearcherBench
# to assess the quality of spatial reasoning generated by the VQASynth pipeline.

# --- Configuration ---

# Define the rubric for what constitutes good spatial reasoning.
# This is inspired by the expert-designed rubrics in ResearcherBench.
# Scale: 1 (Poor), 2 (Good), 3 (Excellent)
SPATIAL_REASONING_RUBRIC = {
    "criteria": [
        {
            "name": "Object Identification",
            "weight": 0.2,
            "description": "Accurately identifies and grounds the key objects from the question within the scene."
        },
        {
            "name": "Spatial Logic",
            "weight": 0.4,
            "description": "Applies a logical, step-by-step process using correct spatial relationships (e.g., 'left of', 'behind', 'closer to'). The reasoning process is coherent and easy to follow."
        },
        {
            "name": "Metric Plausibility",
            "weight": 0.3,
            "description": "If a quantitative estimate is required, the reasoning provides a plausible number justified by referencing common-sense object sizes or visual cues."
        },
        {
            "name": "Groundedness",
            "weight": 0.1,
            "description": "The reasoning explicitly connects back to visual evidence described in the image, rather than being purely abstract."
        }
    ],
    "scoring_instructions": "For each criterion, provide a score from 1 to 3. Output a single JSON object with a 'scores' key, which is a dictionary mapping criterion names to their integer scores. Do not include any other text or explanations."
}

# The prompt for the "Judge" LLM, inspired by ResearcherBench's evaluation prompts.
JUDGE_PROMPT_TEMPLATE = """
You are an expert AI evaluator. Your task is to assess the quality of a VLM's spatial reasoning process based on a provided rubric.

**Question:**
{question}

**Reasoning to Evaluate:**
{reasoning}

**Evaluation Rubric:**
{rubric}

**Instructions:**
{instructions}

**Your JSON Output:**
"""

def extract_thinking_block(response_text):
    """Extracts content from the <think>...</think> block."""
    match = re.search(r'<think>(.*?)</think>', response_text, re.DOTALL)
    if match:
        return match.group(1).strip()
    return None

def evaluate_reasoning(client, question, reasoning_text):
    """
    Uses a powerful LLM as a judge to evaluate reasoning text against the rubric.
    This function mirrors the core logic of ResearcherBench's `rubric_eval/evaluator.py`.
    """
    if not reasoning_text:
        return None

    rubric_str = json.dumps(SPATIAL_REASONING_RUBRIC['criteria'], indent=2)
    prompt = JUDGE_PROMPT_TEMPLATE.format(
        question=question,
        reasoning=reasoning_text,
        rubric=rubric_str,
        instructions=SPATIAL_REASONING_RUBRIC['scoring_instructions']
    )

    try:
        response = client.chat.completions.create(
            model="gpt-4-turbo",  # A powerful model is needed for reliable judging
            messages=[{"role": "user", "content": prompt}],
            temperature=0.0,
            response_format={"type": "json_object"}
        )
        result_json = json.loads(response.choices[0].message.content)
        
        # Calculate weighted score
        total_score = 0
        for criterion in SPATIAL_REASONING_RUBRIC['criteria']:
            name = criterion['name']
            weight = criterion['weight']
            score = result_json.get('scores', {}).get(name, 0)
            total_score += score * weight
            
        return {"weighted_score": total_score, "details": result_json.get('scores', {})}

    except Exception as e:
        print(f"Error during evaluation: {e}")
        return None

def main():
    parser = argparse.ArgumentParser(description="Evaluate VQASynth reasoning quality using a rubric.")
    parser.add_argument("--input_file", type=str, required=True, help="Path to the VQASynth-generated dataset JSON file.")
    parser.add_argument("--api_key", type=str, help="OpenAI API key. Defaults to OPENAI_API_KEY env var.")
    parser.add_argument("--output_file", type=str, default="evaluation_results.json", help="Path to save the detailed evaluation results.")
    parser.add_argument("--limit", type=int, default=10, help="Number of samples to evaluate. Default is 10.")
    args = parser.parse_args()

    api_key = args.api_key or os.getenv("OPENAI_API_KEY")
    if not api_key:
        raise ValueError("OpenAI API key must be provided via --api_key or OPENAI_API_KEY environment variable.")
    
    client = OpenAI(api_key=api_key)

    try:
        with open(args.input_file, 'r') as f:
            data = json.load(f)
    except FileNotFoundError:
        print(f"Error: Input file not found at {args.input_file}")
        return
    except json.JSONDecodeError:
        print(f"Error: Could not decode JSON from {args.input_file}")
        return

    all_results = []
    total_scores = []
    
    # Process a limited number of samples for the experiment
    samples_to_process = data[:args.limit]

    for i, item in enumerate(samples_to_process):
        # Assumes VQASynth output format has 'conversations'
        if 'conversations' not in item or len(item['conversations']) < 2:
            continue
        
        question = item['conversations'][0]['value']
        response_text = item['conversations'][1]['value']
        
        reasoning_text = extract_thinking_block(response_text)
        
        if not reasoning_text:
            print(f"Skipping sample {i+1} (ID: {item.get('id', 'N/A')}), no <think> block found.")
            continue

        print(f"Evaluating sample {i+1}/{len(samples_to_process)}...")
        evaluation = evaluate_reasoning(client, question, reasoning_text)

        if evaluation:
            all_results.append({
                "id": item.get('id', f"sample_{i}"),
                "question": question,
                "reasoning": reasoning_text,
                "evaluation": evaluation
            })
            total_scores.append(evaluation["weighted_score"])

    if not total_scores:
        print("No samples were successfully evaluated.")
        return

    # Save detailed results
    with open(args.output_file, 'w') as f:
        json.dump(all_results, f, indent=2)
    
    print("\n--- Evaluation Complete ---")
    print(f"Detailed results saved to: {args.output_file}")
    print(f"Average Quality Score: {mean(total_scores):.3f}")
    print("---------------------------\n")


if __name__ == "__main__":
    main()
